import{_ as a,c as i,o as e,ah as r}from"./chunks/framework.Cnj7lwEt.js";const b=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/AI工具/openclaw-AI工具.md","filePath":"github汇总/AI工具/openclaw-AI工具.md"}'),o={name:"github汇总/AI工具/openclaw-AI工具.md"};function n(t,l,h,s,d,c){return e(),i("div",null,l[0]||(l[0]=[r('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>OpenClaw</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Peter Steinberger和社区</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>AI工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>需要一个个人的、本地运行的AI助手，能够在多种消息平台上提供服务，支持语音交互和可视化功能。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><p>个人AI助手，可在多种消息平台上运行，支持语音交互和Canvas功能，提供本地优先的控制平面。</p><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>多通道支持：WhatsApp、Telegram、Slack、Discord等多种消息平台</li><li>语音交互：macOS/iOS/Android上的语音唤醒和对话模式</li><li>实时Canvas：可控制的可视化工作区</li><li>本地优先：在自己的设备上运行</li><li>多代理路由：将入站通道/账户/对等方路由到隔离的代理</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">https://github.com/openclaw/openclaw</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于需要个人AI助手，希望在多种消息平台上使用AI功能的用户。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>Node.js ≥22</li><li>npm、pnpm或bun</li><li>支持的平台：macOS、Linux、Windows (via WSL2)</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><ol><li><p><strong>安装OpenClaw</strong></p><ul><li>目标：全局安装OpenClaw</li><li>位置：命令行</li><li>命令：<code>npm install -g openclaw@latest</code> 或 <code>pnpm add -g openclaw@latest</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查Node.js版本是否符合要求</li></ul></li><li><p><strong>运行onboarding向导</strong></p><ul><li>目标：设置网关、工作区、通道和技能</li><li>位置：命令行</li><li>命令：<code>openclaw onboard --install-daemon</code></li><li>成功标志：向导完成，Gateway守护进程安装成功</li><li>失败处理：检查权限，确保有足够的权限安装守护进程</li></ul></li><li><p><strong>启动Gateway</strong></p><ul><li>目标：启动OpenClaw Gateway</li><li>位置：命令行</li><li>命令：<code>openclaw gateway --port 18789 --verbose</code></li><li>成功标志：Gateway启动成功，显示WebSocket地址</li><li>失败处理：检查端口是否被占用，查看日志排查错误</li></ul></li><li><p><strong>发送消息测试</strong></p><ul><li>目标：测试OpenClaw的消息发送功能</li><li>位置：命令行</li><li>命令：<code>openclaw message send --to +1234567890 --message &quot;Hello from OpenClaw&quot;</code></li><li>成功标志：消息发送成功</li><li>失败处理：检查通道配置是否正确</li></ul></li><li><p><strong>与助手对话</strong></p><ul><li>目标：测试与AI助手的对话功能</li><li>位置：命令行</li><li>命令：<code>openclaw agent --message &quot;Ship checklist&quot; --thinking high</code></li><li>成功标志：助手返回响应</li><li>失败处理：检查模型配置是否正确</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>访问地址：WebSocket地址（默认 ws://127.0.0.1:18789）</li><li>检查命令：运行测试命令</li><li>预期返回：助手响应正常</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>Node.js版本不兼容</strong></p><ul><li>现象：安装或运行失败</li><li>可能原因：Node.js版本低于22</li><li>解决步骤：升级Node.js到22或更高版本</li></ul></li><li><p><strong>端口被占用</strong></p><ul><li>现象：Gateway启动失败</li><li>可能原因：端口18789已被占用</li><li>解决步骤：使用不同的端口，或关闭占用该端口的进程</li></ul></li><li><p><strong>通道配置错误</strong></p><ul><li>现象：消息发送失败</li><li>可能原因：通道配置不正确，如API密钥缺失</li><li>解决步骤：检查通道配置，确保API密钥正确设置</li></ul></li><li><p><strong>权限问题</strong></p><ul><li>现象：守护进程安装失败</li><li>可能原因：权限不足</li><li>解决步骤：使用管理员权限运行命令</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><ul><li><strong>从源代码构建</strong>：克隆仓库并使用pnpm构建</li><li><strong>Docker部署</strong>：使用Docker容器运行</li><li><strong>Nix模式</strong>：使用Nix进行声明式配置</li></ul><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中提供了详细的安装和配置指南，可参考官方文档获取更多信息。</p>',31)]))}const g=a(o,[["render",n]]);export{b as __pageData,g as default};
